/**
 * Builder for {@link ExtendClient} - not auto-generated by Fern.
 *
 * <p>Fern generates {@link ExtendClientBaseBuilder}; this hand-written builder keeps the
 * historical {@code ExtendClientBuilder} type name and overrides every setter with a
 * covariant return type so fluent chains keep returning {@code ExtendClientBuilder} and
 * {@link #build()} keeps returning {@link ExtendClient}.</p>
 */
package ai.extend;

import ai.extend.core.Environment;
import okhttp3.OkHttpClient;

/**
 * Builder for {@link ExtendClient}.
 *
 * <p>Exposes all standard options (token, environment, url, timeout, maxRetries, etc.) plus
 * the {@code apiKey} / {@code baseUrl} convenience aliases.</p>
 */
public class ExtendClientBuilder extends ExtendClientBaseBuilder {

    /**
     * Sets the API key (convenience alias for {@link #token(String)}).
     */
    public ExtendClientBuilder apiKey(String apiKey) {
        super.token(apiKey);
        return this;
    }

    /**
     * Sets a custom base URL (convenience alias for {@link #url(String)}).
     */
    public ExtendClientBuilder baseUrl(String baseUrl) {
        super.url(baseUrl);
        return this;
    }

    @Override
    public ExtendClientBuilder token(String token) {
        super.token(token);
        return this;
    }

    @Override
    public ExtendClientBuilder extendApiVersion(String extendApiVersion) {
        super.extendApiVersion(extendApiVersion);
        return this;
    }

    @Override
    public ExtendClientBuilder environment(Environment environment) {
        super.environment(environment);
        return this;
    }

    @Override
    public ExtendClientBuilder url(String url) {
        super.url(url);
        return this;
    }

    @Override
    public ExtendClientBuilder timeout(int timeout) {
        super.timeout(timeout);
        return this;
    }

    @Override
    public ExtendClientBuilder maxRetries(int maxRetries) {
        super.maxRetries(maxRetries);
        return this;
    }

    @Override
    public ExtendClientBuilder httpClient(OkHttpClient httpClient) {
        super.httpClient(httpClient);
        return this;
    }

    @Override
    public ExtendClientBuilder addHeader(String name, String value) {
        super.addHeader(name, value);
        return this;
    }

    @Override
    public ExtendClient build() {
        return new ExtendClient(buildClientOptions());
    }
}
